+                </p>
+              </>
+            ) : (
+              <>
+                <p className="text-muted-foreground">No entries match your search.</p>
+                <button
+                  type="button"
+                  onClick={() => {
+                    setSearchQuery("");
+                    setSelectedDeathType(null);
+                  }}
+                  className="mt-4 text-primary hover:underline"
+                >
+                  Clear filters
+                </button>
+              </>
+            )}
+          </motion.div>
+        )}
+      </div>
+    </div>
+  );
+}

